/**
 * VirtualClock adapter tests — DoD 4
 */

import { describe, it, expect } from "vitest";
import { createVirtualClock, createClockRangeError } from "../src/testing/virtual-clock.js";

const DEFAULT_WALL_CLOCK = 1707753600000; // 2024-02-12T12:00:00Z

// =============================================================================
// DoD 4: Virtual Clock Adapter
// =============================================================================

describe("VirtualClock", () => {
  it("createVirtualClock() with defaults: monotonicNow returns 0", () => {
    const clock = createVirtualClock();
    expect(clock.monotonicNow()).toBe(0);
  });

  it("createVirtualClock() with defaults: wallClockNow returns default epoch", () => {
    const clock = createVirtualClock();
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK);
  });

  it("createVirtualClock() with custom options uses provided values", () => {
    const clock = createVirtualClock({ initialMonotonic: 500, initialWallClock: 1000000000000 });
    expect(clock.monotonicNow()).toBe(500);
    expect(clock.wallClockNow()).toBe(1000000000000);
  });

  it("advance() moves all three time functions forward", () => {
    const clock = createVirtualClock({ initialMonotonic: 0, initialWallClock: DEFAULT_WALL_CLOCK });
    const m0 = clock.monotonicNow();
    const w0 = clock.wallClockNow();
    const h0 = clock.highResNow();

    clock.advance(100);

    expect(clock.monotonicNow()).toBe(m0 + 100);
    expect(clock.wallClockNow()).toBe(w0 + 100);
    expect(clock.highResNow()).toBe(h0 + 100);
  });

  it("advance() with 0 is a no-op", () => {
    const clock = createVirtualClock({ initialMonotonic: 0 });
    clock.advance(0);
    expect(clock.monotonicNow()).toBe(0);
  });

  it("advance() with negative value returns err(ClockRangeError)", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-1);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(result.error._tag).toBe("ClockRangeError");
      expect(result.error.value).toBe(-1);
    }
  });

  it("set() updates only specified time functions", () => {
    const clock = createVirtualClock({
      initialMonotonic: 100,
      initialWallClock: DEFAULT_WALL_CLOCK,
      initialHighRes: DEFAULT_WALL_CLOCK,
    });
    clock.set({ monotonic: 999 });
    expect(clock.monotonicNow()).toBe(999);
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK);
  });

  it("set() with empty object is a no-op", () => {
    const clock = createVirtualClock({ initialMonotonic: 42 });
    clock.set({});
    expect(clock.monotonicNow()).toBe(42);
  });

  it("jumpWallClock() moves wallClock and highRes but not monotonic", () => {
    const clock = createVirtualClock({
      initialMonotonic: 100,
      initialWallClock: DEFAULT_WALL_CLOCK,
    });
    const mono0 = clock.monotonicNow();
    clock.jumpWallClock(5000);
    expect(clock.monotonicNow()).toBe(mono0);
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK + 5000);
    expect(clock.highResNow()).toBe(DEFAULT_WALL_CLOCK + 5000);
  });

  it("jumpWallClock() with negative value moves time backward", () => {
    const clock = createVirtualClock({ initialWallClock: DEFAULT_WALL_CLOCK });
    clock.jumpWallClock(-1000);
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK - 1000);
  });

  it("determinism: two instances with same operations produce same results", () => {
    const clock1 = createVirtualClock({ initialMonotonic: 0, initialWallClock: 1000000 });
    const clock2 = createVirtualClock({ initialMonotonic: 0, initialWallClock: 1000000 });

    clock1.advance(100);
    clock2.advance(100);

    expect(clock1.monotonicNow()).toBe(clock2.monotonicNow());
    expect(clock1.wallClockNow()).toBe(clock2.wallClockNow());
  });

  it("createVirtualClock() throws TypeError when initialMonotonic is NaN", () => {
    expect(() => createVirtualClock({ initialMonotonic: NaN })).toThrow(TypeError);
  });

  it("createVirtualClock() throws TypeError when initialWallClock is Infinity", () => {
    expect(() => createVirtualClock({ initialWallClock: Infinity })).toThrow(TypeError);
  });

  it("createVirtualClock() accepts negative initialMonotonic without error", () => {
    expect(() => createVirtualClock({ initialMonotonic: -100 })).not.toThrow();
  });

  it("set() throws TypeError when any field is NaN", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ monotonic: NaN })).toThrow(TypeError);
    expect(() => clock.set({ wallClock: NaN })).toThrow(TypeError);
    expect(() => clock.set({ highRes: NaN })).toThrow(TypeError);
  });

  it("set() throws TypeError when any field is Infinity or -Infinity", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ monotonic: Infinity })).toThrow(TypeError);
    expect(() => clock.set({ wallClock: -Infinity })).toThrow(TypeError);
  });

  it("set() accepts negative values without error", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ monotonic: -100 })).not.toThrow();
    expect(() => clock.set({ wallClock: -500 })).not.toThrow();
  });

  it("advance() with negative: returned err contains ClockRangeError with _tag 'ClockRangeError'", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-5);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(result.error._tag).toBe("ClockRangeError");
    }
  });

  it("advance() with negative: returned ClockRangeError is frozen", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-5);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(Object.isFrozen(result.error)).toBe(true);
    }
  });

  it("advance() with negative: ClockRangeError includes parameter, value, and message fields", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-42);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(typeof result.error.parameter).toBe("string");
      expect(result.error.value).toBe(-42);
      expect(typeof result.error.message).toBe("string");
    }
  });

  it("VirtualClockAdapter does not access system clock after construction", () => {
    const clock = createVirtualClock({ initialMonotonic: 100, initialWallClock: 5000 });
    // Read before "tampering" with globals
    const m1 = clock.monotonicNow();
    const w1 = clock.wallClockNow();
    const h1 = clock.highResNow();

    // The VirtualClock uses internal state, not Date.now() or performance.now()
    expect(m1).toBe(100);
    expect(w1).toBe(5000);
    expect(h1).toBe(5000); // defaults highRes to initialWallClock
  });

  it("createClockRangeError() returns a frozen object with _tag 'ClockRangeError'", () => {
    const error = createClockRangeError("ms", -1, "test error");
    expect(error._tag).toBe("ClockRangeError");
    expect(Object.isFrozen(error)).toBe(true);
  });
});

// =============================================================================
// DoD 4: Auto-Advance on Read
// =============================================================================

describe("VirtualClock auto-advance", () => {
  it("createVirtualClock({ autoAdvance: 10 }): first monotonicNow() returns 0, second returns 10", () => {
    const clock = createVirtualClock({ initialMonotonic: 0, autoAdvance: 10 });
    expect(clock.monotonicNow()).toBe(0);
    expect(clock.monotonicNow()).toBe(10);
  });

  it("createVirtualClock({ autoAdvance: 10 }): wallClockNow() also advances by 10 on each read", () => {
    const clock = createVirtualClock({ initialWallClock: DEFAULT_WALL_CLOCK, autoAdvance: 10 });
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK);
    expect(clock.wallClockNow()).toBe(DEFAULT_WALL_CLOCK + 10);
  });

  it("createVirtualClock({ autoAdvance: 10 }): highResNow() also advances by 10 on each read", () => {
    const clock = createVirtualClock({ initialHighRes: DEFAULT_WALL_CLOCK, autoAdvance: 10 });
    expect(clock.highResNow()).toBe(DEFAULT_WALL_CLOCK);
    expect(clock.highResNow()).toBe(DEFAULT_WALL_CLOCK + 10);
  });

  it("setAutoAdvance(0) disables auto-advance", () => {
    const clock = createVirtualClock({ initialMonotonic: 0, autoAdvance: 10 });
    clock.setAutoAdvance(0);
    const v1 = clock.monotonicNow();
    const v2 = clock.monotonicNow();
    expect(v1).toBe(v2);
  });

  it("setAutoAdvance(5) overrides construction option", () => {
    const clock = createVirtualClock({ initialMonotonic: 0, autoAdvance: 10 });
    clock.setAutoAdvance(5);
    expect(clock.monotonicNow()).toBe(0);
    expect(clock.monotonicNow()).toBe(5);
  });

  it("getAutoAdvance() returns the current auto-advance value", () => {
    const clock = createVirtualClock({ autoAdvance: 7 });
    expect(clock.getAutoAdvance()).toBe(7);
    clock.setAutoAdvance(3);
    expect(clock.getAutoAdvance()).toBe(3);
  });

  it("auto-advance returns value BEFORE advancing (read-then-advance semantics)", () => {
    const clock = createVirtualClock({ initialMonotonic: 100, autoAdvance: 10 });
    // First call returns 100 (current), then advances to 110
    const firstRead = clock.monotonicNow();
    expect(firstRead).toBe(100);
    // Second call returns 110, then advances to 120
    const secondRead = clock.monotonicNow();
    expect(secondRead).toBe(110);
  });

  it("setAutoAdvance() throws TypeError for negative value", () => {
    const clock = createVirtualClock();
    expect(() => clock.setAutoAdvance(-1)).toThrow(TypeError);
  });

  it("createVirtualClock() throws TypeError when autoAdvance is NaN", () => {
    expect(() => createVirtualClock({ autoAdvance: NaN })).toThrow(TypeError);
  });
});

// =============================================================================
// Mutation score improvement — error messages and boundary conditions
// =============================================================================

describe("VirtualClock — option validation error messages", () => {
  it("initialMonotonic: NaN throws message containing 'must be a finite'", () => {
    expect(() => createVirtualClock({ initialMonotonic: NaN }))
      .toThrow(/must be a finite/);
  });

  it("initialMonotonic: Infinity throws message containing 'initialMonotonic'", () => {
    expect(() => createVirtualClock({ initialMonotonic: Infinity }))
      .toThrow(/initialMonotonic/);
  });

  it("initialWallClock: Infinity throws message containing 'initialWallClock'", () => {
    expect(() => createVirtualClock({ initialWallClock: Infinity }))
      .toThrow(/initialWallClock/);
  });

  it("initialHighRes: Infinity throws TypeError", () => {
    expect(() => createVirtualClock({ initialHighRes: Infinity })).toThrow(TypeError);
  });

  it("initialHighRes: NaN throws message containing 'initialHighRes'", () => {
    expect(() => createVirtualClock({ initialHighRes: NaN }))
      .toThrow(/initialHighRes/);
  });

  it("autoAdvance: -1 (via constructor) throws TypeError", () => {
    expect(() => createVirtualClock({ autoAdvance: -1 })).toThrow(TypeError);
  });

  it("autoAdvance: -1 (via constructor) throws message containing 'autoAdvance'", () => {
    expect(() => createVirtualClock({ autoAdvance: -1 }))
      .toThrow(/autoAdvance/);
  });

  it("autoAdvance: 0 (via constructor) is valid — does NOT throw", () => {
    expect(() => createVirtualClock({ autoAdvance: 0 })).not.toThrow();
  });

  it("setAutoAdvance(-1) throws message containing 'non-negative'", () => {
    const clock = createVirtualClock();
    expect(() => clock.setAutoAdvance(-1)).toThrow(/non-negative/);
  });
});

describe("VirtualClock — advance() error message content", () => {
  it("advance(-1) error.parameter is 'ms'", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-1);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(result.error.parameter).toBe("ms");
    }
  });

  it("advance(-1) error.message contains 'non-negative'", () => {
    const clock = createVirtualClock();
    const result = clock.advance(-1);
    expect(result.isErr()).toBe(true);
    if (result.isErr()) {
      expect(result.error.message).toMatch(/non-negative/);
    }
  });
});

describe("VirtualClock — set() and jumpWallClock() error messages", () => {
  it("set({ monotonic: NaN }) throws message containing 'monotonic'", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ monotonic: NaN })).toThrow(/monotonic/);
  });

  it("set({ wallClock: NaN }) throws message containing 'wallClock'", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ wallClock: NaN })).toThrow(/wallClock/);
  });

  it("set({ highRes: Infinity }) throws TypeError", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ highRes: Infinity })).toThrow(TypeError);
  });

  it("set({ highRes: NaN }) throws message containing 'highRes'", () => {
    const clock = createVirtualClock();
    expect(() => clock.set({ highRes: NaN })).toThrow(/highRes/);
  });

  it("jumpWallClock(NaN) throws TypeError", () => {
    const clock = createVirtualClock();
    expect(() => clock.jumpWallClock(NaN)).toThrow(TypeError);
  });

  it("jumpWallClock(Infinity) throws TypeError", () => {
    const clock = createVirtualClock();
    expect(() => clock.jumpWallClock(Infinity)).toThrow(TypeError);
  });

  it("jumpWallClock(NaN) throws message containing 'finite'", () => {
    const clock = createVirtualClock();
    expect(() => clock.jumpWallClock(NaN)).toThrow(/finite/);
  });
});

describe("VirtualClock — autoAdvance=0 boundary (no spurious advance)", () => {
  it("wallClockNow() does NOT advance when autoAdvanceMs is 0 (default)", () => {
    const clock = createVirtualClock();
    const v1 = clock.wallClockNow();
    const v2 = clock.wallClockNow();
    expect(v1).toBe(v2);
  });

  it("highResNow() does NOT advance when autoAdvanceMs is 0 (default)", () => {
    const clock = createVirtualClock();
    const v1 = clock.highResNow();
    const v2 = clock.highResNow();
    expect(v1).toBe(v2);
  });

  it("after setAutoAdvance(0), wallClockNow() no longer advances", () => {
    const clock = createVirtualClock({ autoAdvance: 10 });
    clock.setAutoAdvance(0);
    const v1 = clock.wallClockNow();
    const v2 = clock.wallClockNow();
    expect(v1).toBe(v2);
  });

  it("after setAutoAdvance(0), highResNow() no longer advances", () => {
    const clock = createVirtualClock({ autoAdvance: 10 });
    clock.setAutoAdvance(0);
    const v1 = clock.highResNow();
    const v2 = clock.highResNow();
    expect(v1).toBe(v2);
  });
});

// =============================================================================
// Mutation score improvement — set() highRes valid value (kills CE true at L178)
// =============================================================================

describe("VirtualClock — set() highRes finite value does NOT throw (kills id=1246)", () => {
  it("set({ highRes: 100 }) with finite value does not throw", () => {
    // CE true mutant at L178: if (!Number.isFinite(values.highRes)) → if (true)
    // → always throws for any highRes value, even valid ones
    // This assertion would fail with the mutation → KILLED
    const clock = createVirtualClock();
    expect(() => clock.set({ highRes: 100 })).not.toThrow();
  });

  it("set({ highRes: 100 }) updates highResNow() to 100", () => {
    const clock = createVirtualClock();
    clock.set({ highRes: 100 });
    expect(clock.highResNow()).toBe(100);
  });

  it("set({ highRes: 0 }) is valid and updates highResNow()", () => {
    const clock = createVirtualClock({ initialHighRes: 999 });
    expect(() => clock.set({ highRes: 0 })).not.toThrow();
    expect(clock.highResNow()).toBe(0);
  });
});

